// ValueIDString retrieves an enum value from the enum constants string name.
// Throws an error if the param is not part of the enum.
func ValueIDString(s string) (ValueID, error) {
	if val, ok := _ValueIDNameToValueMap[s]; ok {
		return val, nil
	}

	if val, ok := _ValueIDNameToValueMap[strings.ToLower(s)]; ok {
		return val, nil
	}
	return 0, fmt.Errorf("%s does not belong to ValueID values", s)
}

// ValueIDValues returns all values of the enum
func ValueIDValues() []ValueID {
	return _ValueIDValues
}

// ValueIDStrings returns a slice of all String values of the enum
func ValueIDStrings() []string {
	strs := make([]string, len(_ValueIDNames))
	copy(strs, _ValueIDNames)
	return strs
}

// IsAValueID returns "true" if the value is listed in the enum definition. "false" otherwise
func (i ValueID) IsAValueID() bool {
	for _, v := range _ValueIDValues {
		if i == v {
			return true
		}
	}
	return false
}
